(991, 10, '生物危害', '生物危害隐患排查', '较大', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(992, 10, '病原微生物暴露', '病原微生物暴露隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(993, 10, '布鲁氏菌病风险', '布鲁氏菌病风险隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(994, 10, '炭疽病风险', '炭疽病风险隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(995, 10, '禽流感职业暴露', '禽流感职业暴露隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(996, 10, '人畜共患病暴露', '人畜共患病暴露隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(997, 10, '医废职业暴露', '医废职业暴露隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(998, 10, '传染病职业暴露', '传染病职业暴露隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(999, 10, '结核病暴露', '结核病暴露隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1000, 10, '艾滋病暴露', '艾滋病暴露隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1001, 10, '硫化氢中毒风险', '硫化氢中毒风险隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1002, 10, '一氧化碳中毒风险', '一氧化碳中毒风险隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1003, 10, '密闭空间窒息风险', '密闭空间窒息风险隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1004, 10, '缺氧环境风险', '缺氧环境风险隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1005, 10, '有害气体急性中毒', '有害气体急性中毒隐患排查', '重大', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1006, 10, '有机溶剂中毒', '有机溶剂中毒隐患排查', '较大', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1007, 10, '正己烷中毒', '正己烷中毒隐患排查', '一般', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1008, 10, '三氯乙烯中毒', '三氯乙烯中毒隐患排查', '重大', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1009, 10, '二甲基甲酰胺中毒', '二甲基甲酰胺中毒隐患排查', '较大', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1010, 10, '丙酮中毒', '丙酮中毒隐患排查', '一般', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1011, 10, '重金属中毒', '重金属中毒隐患排查', '重大', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1012, 10, '铅中毒', '铅中毒隐患排查', '较大', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1013, 10, '汞中毒', '汞中毒隐患排查', '一般', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1014, 10, '镉中毒', '镉中毒隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1015, 10, '锰中毒', '锰中毒隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1016, 10, '铍中毒', '铍中毒隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1017, 10, '职业性皮肤病', '职业性皮肤病隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1018, 10, '接触性皮炎', '接触性皮炎隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1019, 10, '电光性皮炎', '电光性皮炎隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1020, 10, '化学性皮肤灼伤', '化学性皮肤灼伤隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1021, 10, '职业性痤疮', '职业性痤疮隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1022, 10, '职业性眼病', '职业性眼病隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1023, 10, '电光性眼炎', '电光性眼炎隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1024, 10, '化学性眼灼伤', '化学性眼灼伤隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1025, 10, '职业性白内障', '职业性白内障隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1026, 10, '辐射性白内障', '辐射性白内障隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1027, 10, '耳鼻喉口腔疾病', '耳鼻喉口腔疾病隐患排查', '较大', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1028, 10, '噪声聋', '噪声聋隐患排查', '一般', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1029, 10, '铬鼻病', '铬鼻病隐患排查', '重大', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1030, 10, '牙酸蚀病', '牙酸蚀病隐患排查', '较大', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1031, 10, '爆震聋', '爆震聋隐患排查', '一般', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1032, 10, '职业性肿瘤', '职业性肿瘤隐患排查', '重大', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1033, 10, '石棉所致肺癌', '石棉所致肺癌隐患排查', '较大', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1034, 10, '苯所致白血病', '苯所致白血病隐患排查', '一般', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1035, 10, '联苯胺所致膀胱癌', '联苯胺所致膀胱癌隐患排查', '重大', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1036, 10, '氯甲醚所致肺癌', '氯甲醚所致肺癌隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1037, 10, '职业性哮喘', '职业性哮喘隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1038, 10, '变态反应性肺泡炎', '变态反应性肺泡炎隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1039, 10, '棉尘病', '棉尘病隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1040, 10, '药物性肺炎', '药物性肺炎隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1041, 10, '劳防用品缺失', '劳防用品缺失隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1042, 10, '防尘口罩不合格', '防尘口罩不合格隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1043, 10, '防毒面具滤毒盒过期', '防毒面具滤毒盒过期隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1044, 10, '防护面罩破损', '防护面罩破损隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1045, 10, '防护眼镜模糊', '防护眼镜模糊隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1046, 10, '防噪耳塞失效', '防噪耳塞失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1047, 10, '防噪耳罩损坏', '防噪耳罩损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1048, 10, '防高温服破损', '防高温服破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1049, 10, '防辐射服屏蔽不足', '防辐射服屏蔽不足隐患排查', '一般', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1050, 10, '作业现场通风不良', '作业现场通风不良隐患排查', '重大', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1051, 10, '局部排风失效', '局部排风失效隐患排查', '较大', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1052, 10, '全面通风不足', '全面通风不足隐患排查', '一般', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1053, 10, '通风管道堵塞', '通风管道堵塞隐患排查', '重大', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1054, 10, '送风口位置不当', '送风口位置不当隐患排查', '较大', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1055, 10, '危害告知不到位', '危害告知不到位隐患排查', '一般', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1056, 10, '健康检查未按规定开展', '健康检查未按规定开展隐患排查', '重大', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1057, 10, '岗前检查缺失', '岗前检查缺失隐患排查', '较大', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1058, 10, '在岗检查超期', '在岗检查超期隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1059, 10, '离岗检查未落实', '离岗检查未落实隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1060, 10, '监护档案不健全', '监护档案不健全隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1061, 10, '危害因素检测未定期开展', '危害因素检测未定期开展隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1062, 10, '检测结果未公示', '检测结果未公示隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1063, 10, '申报不实', '申报不实隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1064, 10, '警示标识缺失', '警示标识缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1065, 10, '中文说明不完整', '中文说明不完整隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1066, 10, '应急救援设施不足', '应急救援设施不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1067, 10, '中毒应急预案缺失', '中毒应急预案缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1068, 10, '急救药品过期', '急救药品过期隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1069, 10, '冲洗设备水压不足', '冲洗设备水压不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1070, 10, '洗眼器损坏', '洗眼器损坏隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1071, 10, '毒物报警器失灵', '毒物报警器失灵隐患排查', '重大', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1072, 10, '报警值设定不当', '报警值设定不当隐患排查', '较大', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1073, 10, '报警器未定期校准', '报警器未定期校准隐患排查', '一般', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1074, 10, '报警系统故障', '报警系统故障隐患排查', '重大', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1075, 10, '诊断程序不合规', '诊断程序不合规隐患排查', '较大', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1076, 10, '报告不及时', '报告不及时隐患排查', '一般', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1077, 10, '未按规定提供诊断资料', '未按规定提供诊断资料隐患排查', '重大', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1078, 10, '女工禁忌岗位安排不当', '女工禁忌岗位安排不当隐患排查', '较大', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1079, 10, '未成年工禁忌岗位安排不当', '未成年工禁忌岗位安排不当隐患排查', '一般', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1080, 10, '孕期女工保护不到位', '孕期女工保护不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1081, 11, '校园围墙破损', '校园围墙破损隐患排查', '较大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1082, 11, '校门未设防冲撞设施', '校门未设防冲撞设施隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1083, 11, '校园监控盲区', '校园监控盲区隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1084, 11, '监控摄像头模糊', '监控摄像头模糊隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1085, 11, '视频存储时间不足', '视频存储时间不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1086, 11, '校园欺凌行为', '校园欺凌行为隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1087, 11, '学生斗殴事件', '学生斗殴事件隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1088, 11, '校外人员闯入', '校外人员闯入隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1089, 11, '门卫保安脱岗', '门卫保安脱岗隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1090, 11, '访客登记不严格', '访客登记不严格隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1091, 11, '易燃品违规存放实验室', '易燃品违规存放实验室隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1092, 11, '化学实验品管理不规范', '化学实验品管理不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1093, 11, '气体钢瓶固定不牢', '气体钢瓶固定不牢隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1094, 11, '实验室通风不良', '实验室通风不良隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1095, 11, '实验废弃物处置不当', '实验废弃物处置不当隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1096, 11, '实验室用电安全隐患', '实验室用电安全隐患隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1097, 11, '实验室消防不足', '实验室消防不足隐患排查', '一般', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1098, 11, '高压灭菌锅安全失效', '高压灭菌锅安全失效隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1099, 11, '建筑物墙体裂缝', '建筑物墙体裂缝隐患排查', '较大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1100, 11, '教学楼台阶破损', '教学楼台阶破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1101, 11, '走廊护栏高度不足', '走廊护栏高度不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1102, 11, '楼梯间照明不足', '楼梯间照明不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1103, 11, '教室门窗玻璃破损', '教室门窗玻璃破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1104, 11, '操场设施损坏', '操场设施损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1105, 11, '篮球架松动', '篮球架松动隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1106, 11, '足球门固定不牢', '足球门固定不牢隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1107, 11, '单双杠锈蚀', '单双杠锈蚀隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1108, 11, '跑道地面破损', '跑道地面破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1109, 11, '运动器材老化', '运动器材老化隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1110, 11, '学生食堂食品安全', '学生食堂食品安全隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1111, 11, '食堂食材过期', '食堂食材过期隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1112, 11, '后厨卫生不达标', '后厨卫生不达标隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1113, 11, '餐具消毒不彻底', '餐具消毒不彻底隐患排查', '重大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1114, 11, '饮用水不达标', '饮用水不达标隐患排查', '较大', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1115, 11, '校车安全', '校车安全隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1116, 11, '校车超员', '校车超员隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1117, 11, '校车资质过期', '校车资质过期隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1118, 11, '校车驾驶员无证', '校车驾驶员无证隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1119, 11, '校车未按规定路线行驶', '校车未按规定路线行驶隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1120, 11, '校车灭火器缺失', '校车灭火器缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1121, 11, '学生宿舍安全', '学生宿舍安全隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1122, 11, '宿舍私拉电线', '宿舍私拉电线隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1123, 11, '宿舍使用违规电器', '宿舍使用违规电器隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1124, 11, '宿舍易燃物堆放', '宿舍易燃物堆放隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1125, 11, '宿舍消防通道堵塞', '宿舍消防通道堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1126, 11, '宿舍门锁损坏', '宿舍门锁损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1127, 11, '管理人员配备不足', '管理人员配备不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1128, 11, '夜不归宿管理缺失', '夜不归宿管理缺失隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1129, 11, '校园交通安全', '校园交通安全隐患排查', '较大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1130, 11, '校内车辆超速', '校内车辆超速隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1131, 11, '校内人车混行', '校内人车混行隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1132, 11, '停车位占用消防通道', '停车位占用消防通道隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1133, 11, '校园门口交通秩序混乱', '校园门口交通秩序混乱隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1134, 11, '自然灾害防范', '自然灾害防范隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1135, 11, '地震演练未开展', '地震演练未开展隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1136, 11, '防震疏散通道不畅', '防震疏散通道不畅隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1137, 11, '防汛设施不完善', '防汛设施不完善隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1138, 11, '防雷设施损坏', '防雷设施损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
