(1596, 16, '取水口堵塞', '取水口堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1597, 16, '取水口淤积', '取水口淤积隐患排查', '较大', '《中华人民共和国防洪法》', '第二十二条', '河道、湖泊管理范围内的土地和岸线的利用，应当符合行洪、输水的要求。禁止在河道、湖泊管理范围内建设妨碍行洪的建筑物、构筑物，倾倒垃圾、渣土，从事影响河势稳定、危害河岸堤防安全和其他妨碍河道行洪的活动。'),
(1598, 16, '取水泵故障', '取水泵故障隐患排查', '一般', '《中华人民共和国防汛条例》', '第十三条', '有防汛任务的县级以上人民政府，应当根据流域综合规划、防洪工程实际状况和国家规定的防洪标准，制定防御洪水方案（包括对特大洪水的处置措施）。'),
(1599, 16, '取水管道破裂', '取水管道破裂隐患排查', '重大', '《中华人民共和国防汛条例》', '第十八条', '山洪、泥石流易发地区，当地人民政府应当指定有关部门进行定期调查和动态监测。发现险情，当地人民政府应当立即采取措施，组织群众转移或者采取其他防护措施。'),
(1600, 16, '输水管道泄漏', '输水管道泄漏隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1601, 16, '输水管道水锤', '输水管道水锤隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1602, 16, '净水厂反应池絮凝效果差', '净水厂反应池絮凝效果差隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1603, 16, '净水厂沉淀池排泥不畅', '净水厂沉淀池排泥不畅隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1604, 16, '净水厂滤池滤料板结', '净水厂滤池滤料板结隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1605, 16, '净水厂滤池反冲洗故障', '净水厂滤池反冲洗故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1606, 16, '净水厂清水池渗漏', '净水厂清水池渗漏隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1607, 16, '净水厂加药计量泵故障', '净水厂加药计量泵故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1608, 16, '净水厂加氯系统故障', '净水厂加氯系统故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1609, 16, '净水厂出水水质超标', '净水厂出水水质超标隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1610, 16, '供水管网爆管', '供水管网爆管隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1611, 16, '供水管网漏损率超标', '供水管网漏损率超标隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1612, 16, '供水管网阀门失灵', '供水管网阀门失灵隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1613, 16, '供水管网消火栓损坏', '供水管网消火栓损坏隐患排查', '一般', '《中华人民共和国防洪法》', '第二十二条', '河道、湖泊管理范围内的土地和岸线的利用，应当符合行洪、输水的要求。禁止在河道、湖泊管理范围内建设妨碍行洪的建筑物、构筑物，倾倒垃圾、渣土，从事影响河势稳定、危害河岸堤防安全和其他妨碍河道行洪的活动。'),
(1614, 16, '二次供水水箱未清洗', '二次供水水箱未清洗隐患排查', '重大', '《中华人民共和国防汛条例》', '第十三条', '有防汛任务的县级以上人民政府，应当根据流域综合规划、防洪工程实际状况和国家规定的防洪标准，制定防御洪水方案（包括对特大洪水的处置措施）。'),
(1615, 16, '二次供水水箱密封不严', '二次供水水箱密封不严隐患排查', '较大', '《中华人民共和国防汛条例》', '第十八条', '山洪、泥石流易发地区，当地人民政府应当指定有关部门进行定期调查和动态监测。发现险情，当地人民政府应当立即采取措施，组织群众转移或者采取其他防护措施。'),
(1616, 16, '二次供水消毒设施故障', '二次供水消毒设施故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1617, 16, '污水管网堵塞', '污水管网堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1618, 16, '污水管网破损', '污水管网破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1619, 16, '污水管网检查井塌陷', '污水管网检查井塌陷隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1620, 16, '污水管网窨井盖丢失', '污水管网窨井盖丢失隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1621, 16, '污水提升泵故障', '污水提升泵故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1622, 16, '雨水管网堵塞', '雨水管网堵塞隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1623, 16, '雨水管网检查井冒溢', '雨水管网检查井冒溢隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1624, 16, '雨水排放口堵塞', '雨水排放口堵塞隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1625, 16, '雨污混接', '雨污混接隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1626, 16, '污水厂进水泵房格栅堵塞', '污水厂进水泵房格栅堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1627, 16, '污水厂沉砂池除砂效果差', '污水厂沉砂池除砂效果差隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
