(1805, 19, '医疗记录错误', '医疗记录错误隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1806, 19, '病历造假', '病历造假隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1807, 19, '医患沟通不足', '医患沟通不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1808, 19, '检查报告错误', '检查报告错误隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1809, 19, '检验结果错误', '检验结果错误隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1810, 19, '病理诊断错误', '病理诊断错误隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1811, 19, '放射诊断错误', '放射诊断错误隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1812, 19, '输血过敏反应', '输血过敏反应隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1813, 19, '输错血型', '输错血型隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1814, 19, '输液速度不当', '输液速度不当隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1815, 19, '药物过敏未问询', '药物过敏未问询隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1816, 19, '药物剂量计算错误', '药物剂量计算错误隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1817, 19, '药物配伍禁忌', '药物配伍禁忌隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1818, 19, '处方错误', '处方错误隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1819, 19, '处方审核不严', '处方审核不严隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1820, 19, '处方调配错误', '处方调配错误隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1821, 19, '发药差错', '发药差错隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1822, 19, '院内感染交叉感染', '院内感染交叉感染隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1823, 19, '院内感染空气传播', '院内感染空气传播隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1824, 19, '院内感染接触传播', '院内感染接触传播隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1825, 19, '院内感染血液传播', '院内感染血液传播隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1826, 19, '医务人员手卫生不达标', '医务人员手卫生不达标隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
